import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Grid } from '@mui/material';
import { PieChart, ResponsiveChartContainer, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface Category {
  name: string;
  itemCount: number;
  estimatedCost: number;
}

interface GroceryData {
  categories: Category[];
  totalEstimatedCost: number;
}

export default function Widget() {
  const groceryData = response.data.data as GroceryData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FF5722' }}>
              Grocery List
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Total Estimated Cost
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#FFC107' }}>
              ${groceryData.totalEstimatedCost.toFixed(2)}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'pie',
                  data: groceryData.categories.map((category) => ({
                    value: category.estimatedCost,
                    label: category.name,
                  })),
                  colorScheme: ['#FF5722', '#FFC107', '#FF9800', '#FFB74D', '#FFD54F'],
                },
              ]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <PieChart />
              </g>
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>

          <Grid container spacing={1}>
            {groceryData.categories.map((category, index) => (
              <Grid item xs={6} key={index}>
                <Box>
                  <Typography variant="body2" fontWeight={500} sx={{ color: '#FF5722' }}>
                    {category.name}
                  </Typography>
                  <Typography variant="caption" color="text.secondary">
                    {category.itemCount} items - ${category.estimatedCost.toFixed(2)}
                  </Typography>
                </Box>
              </Grid>
            ))}
          </Grid>
        </Stack>
      </CardContent>
    </Card>
  );
}
